                    if (nr,nc) in ones and (nr,nc) not in visited:
                        stack.append((nr,nc))
            crosses.append(comp)

    print(f"=== Example {i}: {len(crosses)} crosses ===")
    for j, cross in enumerate(crosses):
        rs = [r for r,c in cross]
        cs = [c for r,c in cross]
        print(f"  Cross {j}: rows {min(rs)}-{max(rs)}, cols {min(cs)}-{max(cs)}")

        # Find adjacent non-8, non-1 cells (trail start)
